// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract SimpleSwap {
    IERC20 public tokenA = IERC20(0xd161478cD39E2dec5E8e0B62de48Ce7C0a531fdE);
    IERC20 public tokenB = IERC20(0xC3aF40042F3EcF76F6Bbd648219F6b9f91A17E0A);

    // 1:1 swap rate (both tokens have 6 decimals)
    uint256 public constant SWAP_RATE = 1;

    event Swap(address indexed user, address indexed tokenIn, uint256 amountIn, uint256 amountOut);

    // Swap tokenA for tokenB
    function swapAForB(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenB.balanceOf(address(this)) >= amount, "Insufficient tokenB in contract");

        tokenA.transferFrom(msg.sender, address(this), amount);
        tokenB.transfer(msg.sender, amount);

        emit Swap(msg.sender, address(tokenA), amount, amount);
    }

    // Swap tokenB for tokenA
    function swapBForA(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenA.balanceOf(address(this)) >= amount, "Insufficient tokenA in contract");

        tokenB.transferFrom(msg.sender, address(this), amount);
        tokenA.transfer(msg.sender, amount);

        emit Swap(msg.sender, address(tokenB), amount, amount);
    }

    // Owner can deposit tokens (you need to approve this contract first)
    function depositTokenA(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenA.balanceOf(msg.sender) >= amount, "Insufficient token balance");

        bool success = tokenA.transferFrom(msg.sender, address(this), amount);
        require(success, "Token transfer failed - check approval");
    }

    function depositTokenB(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenB.balanceOf(msg.sender) >= amount, "Insufficient token balance");

        bool success = tokenB.transferFrom(msg.sender, address(this), amount);
        require(success, "Token transfer failed - check approval");
    }

    // View functions
    function getTokenABalance() external view returns (uint256) {
        return tokenA.balanceOf(address(this));
    }

    function getTokenBBalance() external view returns (uint256) {
        return tokenB.balanceOf(address(this));
    }
}
